import React, { useEffect, useState, useCallback, useRef } from "react";
import axios from "axios";
import { toast, ToastContainer } from "react-toastify";
import { useNavigate } from "react-router-dom";

const DashboardStatement = () => {
  const [showModal, setShowModal] = useState(false);
  const [showStatusModal, setShowStatusModal] = useState(false);
  const [bookingStatement, setBookingStatement] = useState(null);
  const [selectedBooking, setSelectedBooking] = useState(null);
  const [newStatus, setNewStatus] = useState("");
  const [centreBookings, setCentreBookings] = useState([]);
  const [currentPage, setCurrentPage] = useState(1);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedMonth, setSelectedMonth] = useState("");
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());
  const [serviceType, setServiceType] = useState("");
  const [bookingStatus, setBookingStatus] = useState("");
  const navigate = useNavigate();

  const months = [
    { value: "January", label: "January" },
    { value: "February", label: "February" },
    { value: "March", label: "March" },
    { value: "April", label: "April" },
    { value: "May", label: "May" },
    { value: "June", label: "June" },
    { value: "July", label: "July" },
    { value: "August", label: "August" },
    { value: "September", label: "September" },
    { value: "October", label: "October" },
    { value: "November", label: "November" },
    { value: "December", label: "December" },
  ];

  // Generate years (current year to current year + 10)
  const years = Array.from({ length: 11 }, (_, i) => 2025 + i);

  // Fetch centre bookings
  const fetchCentreBookings = async () => {
    try {
      setLoading(true);
      const centreId = localStorage.getItem("centreId");

      if (!centreId) {
        throw new Error("No centreId found in localStorage");
      }

      const response = await axios.get(
        `${process.env.REACT_APP_BACKEND_URL}/api/bookings/centre/${centreId}`
      );

      setCentreBookings(response.data.bookings || []);
      setCurrentPage(1);
      setError(null);
    } catch (err) {
      console.error("Error fetching bookings:", err);
      setError("Failed to load bookings. Please try again later.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCentreBookings();
  }, []);

  const canEnableStatus = (item) => {
    if (item.status.toLowerCase() !== "pending") return false;
    if (!item.appointmentDate || !item.appointmentTime) return false;

    const datePart = item.appointmentDate;
    const startTime = item.appointmentTime.split("-")[0].trim();

    const timeMatch = startTime.match(/(\d+):(\d+)\s*(am|pm)/i);
    if (!timeMatch) return false;

    let [_, hh, mm, period] = timeMatch;
    hh = parseInt(hh, 10);
    mm = parseInt(mm, 10);

    if (period.toLowerCase() === "pm" && hh !== 12) hh += 12;
    if (period.toLowerCase() === "am" && hh === 12) hh = 0;

    const appointmentDateTime = new Date(`${datePart}T${String(hh).padStart(2, "0")}:${String(mm).padStart(2, "0")}:00`);
    const now = new Date();
    return now >= appointmentDateTime;
  };

  const handleCheckBeforeStatus = async (bookingId) => {
    try {
      const response = await fetch(`${process.env.REACT_APP_BACKEND_URL}/api/reports/check/${bookingId}`, {
        method: "GET",
      });

      const data = await response.json();
      const hasFilesOrNotes = (data.files && data.files.length > 0) || data.notes;
      
      return hasFilesOrNotes;
    } catch (error) {
      console.error("Error checking report:", error);
      toast.error("Failed to check report status.");
      return false;
    }
  };

  const shouldDisableCancelButton = (appointmentDate, appointmentTime) => {
    if (!appointmentDate || !appointmentTime) return true;

    const datePart = appointmentDate;
    const startTime = appointmentTime.split("-")[0].trim();

    const timeMatch = startTime.match(/(\d+):(\d+)\s*([ap]\.?m\.?)/i);
    if (!timeMatch) return true;

    let [_, hh, mm, period] = timeMatch;
    hh = parseInt(hh, 10);
    mm = parseInt(mm, 10);

    if (period.toLowerCase() === "pm" && hh !== 12) hh += 12;
    if (period.toLowerCase() === "am" && hh === 12) hh = 0;

    const appointmentDateTime = new Date(`${datePart}T${String(hh).padStart(2, "0")}:${String(mm).padStart(2, "0")}:00`);
    const now = new Date();
    
    const timeDifferenceHours = (appointmentDateTime.getTime() - now.getTime()) / (1000 * 60 * 60);
    
    return timeDifferenceHours <= 2;
  };

  // Update booking status
  const updateStatus = useCallback(async (id, updatedStatus, appointmentDate, appointmentTime) => {
    try {
      const statusLower = updatedStatus.toLowerCase();

      if (statusLower === "completed") {      
        const validationItem = {
          status: "pending",
          appointmentDate,
          appointmentTime
        };
        
        const canEnable = canEnableStatus(validationItem);
        
        if (!canEnable) {
          toast.error("You can only change the status after the appointment time");
          setShowStatusModal(false);
          return;
        }
           
        const hasDocuments = await handleCheckBeforeStatus(id);
        
        if (!hasDocuments) {
          toast.error("Please upload at least one report or note before changing the status to completed");
          setShowStatusModal(false);
          return;
        }
      } else if (statusLower === "cancelled") {
        const canCancel = shouldDisableCancelButton(appointmentDate, appointmentTime);
        
        if (canCancel) {
          toast.error("Cancellation must be done 2+ hours before the appointment time");
          setShowStatusModal(false);
          return;
        }

        const hasDocuments = await handleCheckBeforeStatus(id);
        
        if (hasDocuments) {
          toast.error("Cannot cancel booking as documents have already been uploaded");
          setShowStatusModal(false);
          return;
        }
      }

      await axios.patch(
        `${process.env.REACT_APP_BACKEND_URL}/api/bookings/${id}/status`,
        { status: updatedStatus }
      );

      setCentreBookings((prev) =>
        prev.map((booking) => ({
          ...booking,
          services: booking.services.map((service) =>
            service._id === id ? { ...service, status: updatedStatus } : service
          ),
        }))
      );
      
      toast.success("Status Updated Successfully");
      setShowStatusModal(false);
      setNewStatus("");
      setTimeout(() => {
        fetchBookings();
      }, 3000);
      
    } catch (err) {
      console.error("Error updating status:", err);
      toast.error("Failed to update status");
    }
  }, []);

  const fetchBookings = async () => {
    try {
      setLoading(true);
      const centreId = localStorage.getItem("centreId");

      const response = await axios.get(
        `${process.env.REACT_APP_BACKEND_URL}/api/bookings/searchBooking/Admin`,
        {
          params: {
            status: bookingStatus,
            centreId: centreId,
            month: selectedMonth,
            year: selectedYear,
            serviceType: serviceType
          },
        }
      );

      setCentreBookings(response.data.bookings || []);
      setCurrentPage(1);
    } catch (err) {
      console.error("Error fetching bookings:", err);
      toast.error("Failed to fetch bookings");
    } finally {
      setLoading(false);
    }
  };

  // Apply filters when any filter changes
  useEffect(() => {
    fetchBookings();
  }, [bookingStatus, selectedMonth, selectedYear, serviceType]);

  const handleMonthChange = (e) => {
    setSelectedMonth(e.target.value);
  };

  const handleYearChange = (e) => {
    setSelectedYear(e.target.value);
  };

  const handleServiceTypeChange = (e) => {
    setServiceType(e.target.value);
  };

  const handleStatusChange = (e) => {
    setBookingStatus(e.target.value);
  };

  const flattenedBookings = centreBookings.flatMap((booking) =>
    booking.services.map((item) => ({ booking, item }))
  );

  const packagesPerPage = 10;
  const indexOfLastPackage = currentPage * packagesPerPage;
  const indexOfFirstPackage = indexOfLastPackage - packagesPerPage;
  const currentItems = flattenedBookings.slice(
    indexOfFirstPackage,
    indexOfLastPackage
  );
  const totalPages = Math.ceil(flattenedBookings.length / packagesPerPage);

  const handlePageChange = (pageNumber) => {
    setCurrentPage(pageNumber);
  };

  const handlePageChangeWithScroll = (page) => {
    handlePageChange(page);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const renderPagination = () => {
    const pages = [];
    const maxVisible = 4;
    let startPage = Math.max(1, currentPage - Math.floor(maxVisible / 2));
    let endPage = startPage + maxVisible - 1;

    if (endPage > totalPages) {
      endPage = totalPages;
      startPage = Math.max(1, endPage - maxVisible + 1);
    }

    pages.push(
      <li key="first" className={`page-item ${currentPage === 1 ? " disabled" : ""}`}>
        <button
          className="page-link"
          onClick={() => currentPage !== 1 && handlePageChangeWithScroll(1)}
        >
          First
        </button>
      </li>
    );

    pages.push(
      <li key="prev" className={`page-item ${currentPage === 1 ? "disabled" : ""}`}>
        <button
          className="page-link"
          onClick={() => currentPage > 1 && handlePageChangeWithScroll(currentPage - 1)}
        >
          Prev
        </button>
      </li>
    );

    for (let i = startPage; i <= endPage; i++) {
      pages.push(
        <li key={i} className={`page-item ${currentPage === i ? "active" : ""}`}>
          <button className="page-link" onClick={() => handlePageChangeWithScroll(i)}>
            {i}
          </button>
        </li>
      );
    }

    pages.push(
      <li key="next" className={`page-item ${currentPage === totalPages ? "disabled" : ""}`}>
        <button
          className="page-link"
          onClick={() => currentPage < totalPages && handlePageChangeWithScroll(currentPage + 1)}
        >
          Next
        </button>
      </li>
    );

    pages.push(
      <li key="last" className={`page-item ${currentPage === totalPages ? "disabled" : ""}`}>
        <button
          className="page-link"
          onClick={() => handlePageChangeWithScroll(totalPages)}
        >
          Last
        </button>
      </li>
    );

    return pages;
  };

  const modalRef = useRef(null);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (modalRef.current && !modalRef.current.contains(event.target) && showModal) {
        setShowModal(false);
      }
    };

    document.addEventListener("mousedown", handleClickOutside);

    if (showModal) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "auto";
    }

    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
      document.body.style.overflow = "auto";
    };
  }, [showModal]);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (modalRef.current && !modalRef.current.contains(event.target) && showStatusModal) {
        setShowStatusModal(false);
      }
    };

    document.addEventListener("mousedown", handleClickOutside);

    if (showStatusModal) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "auto";
    }

    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
      document.body.style.overflow = "auto";
    };
  }, [showStatusModal]);

  const getStatusBadgeClass = (status) => {
    const statusLower = status.toLowerCase();
    if (statusLower === "confirmed" || statusLower === "completed")
      return "bg-success";
    if (statusLower === "cancelled") return "bg-danger";
    if (statusLower === "pending") return "bg-warning";
    return "bg-secondary";
  };

  const handleStatusModalOpen = (item) => {
    setSelectedBooking(item);
    setNewStatus(item.status);
    setShowStatusModal(true);
  };

  const handleViewModalOpen = (booking, item) => {
    setBookingStatement({ booking, item });
    setShowModal(true);
  };

  // Clear all filters
  const handleClearFilters = () => {
    setServiceType("");
    setBookingStatus("");
    setSelectedMonth("");
    setSelectedYear(new Date().getFullYear());
  };

  if (loading) {
    return (
      <div className="dashboard-body__content">
        <div className="text-center py-5">Loading bookings...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="dashboard-body__content">
        <div className="alert alert-danger" role="alert">
          {error}
        </div>
      </div>
    );
  }

  return (
    <div className="dashboard-body__content">
      {/* Statement section start */}
      <div className="row gy-4">
        <div className="col-12">
          <div className="card common-card border border-gray-five">
            <div className="card-body">
              {/* Filter Section - Improved Layout */}
              <div className="filters-container mb-4">
                <div className="d-flex flex-wrap align-items-center gap-3">
                  <h4 className="booking-heading mb-0 me-auto">Booking Statement</h4>
                  
                  {/* Service Type Filter */}
                  <div className="filter-item">
                    <select
                      className="common-input border-gray-five filter-select"
                      value={serviceType}
                      onChange={handleServiceTypeChange}
                    >
                      <option value="">All Service Types</option>
                      <option value="service">Service</option>
                      <option value="package">Package</option>
                    </select>
                  </div>

                  {/* Status Filter */}
                  <div className="filter-item">
                    <select
                      className="common-input border-gray-five filter-select"
                      value={bookingStatus}
                      onChange={handleStatusChange}
                    >
                      <option value="">All Status</option>
                      <option value="Cancelled">Cancelled</option>
                      <option value="Completed">Completed</option>
                      <option value="pending">Upcoming</option>
                    </select>
                  </div>

                  {/* Month Filter */}
                  <div className="filter-item">
                    <select
                      className="common-input border-gray-five filter-select"
                      value={selectedMonth}
                      onChange={handleMonthChange}
                    >
                      <option value="">All Months</option>
                      {months.map((m) => (
                        <option key={m.value} value={m.value}>
                          {m.label}
                        </option>
                      ))}
                    </select>
                  </div>

                  {/* Year Filter */}
                  <div className="filter-item">
                    <select
                      className="common-input border-gray-five filter-select"
                      value={selectedYear}
                      onChange={handleYearChange}
                    >
                      {years.map((year) => (
                        <option key={year} value={year}>
                          {year}
                        </option>
                      ))}
                    </select>
                  </div>

                  {/* Clear Filters Button */}
                  {(serviceType || bookingStatus || selectedMonth) && (
                    <button
                      className="btn btn-outline-secondary btn-sm"
                      onClick={handleClearFilters}
                    >
                      Clear Filters
                    </button>
                  )}
                </div>
              </div>

              {flattenedBookings.length === 0 ? (
                <div className="text-center py-5">
                  No bookings found for your centre.
                </div>
              ) : (
                <>
                  <div className="table-responsive">
                    <table className="table text-body mt--24">
                      <thead>
                        <tr>
                          <th>Booking Date</th>
                          <th>Booking ID</th>
                          <th>Appointment Date</th>
                          <th>Time slots</th>
                          <th>Patient Name</th>
                          <th>Patient Email</th>
                          <th>Patient Mobile</th>
                          <th>Service Type</th>
                          <th>Service Name</th>
                          <th>Price</th>
                          <th>Status</th>
                          <th className="text-center">Action</th>
                        </tr>
                      </thead>
                      <tbody>
                        {currentItems.map(({ booking, item }, index) => (
                          <tr key={`${booking._id}-${item._id}-${index}`}>
                            <td>{new Date(booking?.bookingDate).toLocaleString()}</td>
                            <td>{item.bookingId}</td>
                            <td data-label="Date">{item.appointmentDate}</td>
                            <td data-label="Time">{item.appointmentTime}</td>
                            <td
                              data-label="Patient Name"
                              onClick={() => {
                                navigate(`/user-medical-history/${booking?.userDetails?._id}`);
                              }}
                              style={{
                                color: "blue",
                                textDecoration: "underline",
                                cursor: "pointer",
                              }}
                            >
                              {booking.userDetails.firstName} {booking.userDetails.lastName}
                            </td>
                            <td data-label="Patient Email">{booking.userDetails.email}</td>
                            <td data-label="Patient Mobile">{booking.userDetails.mobileNumber}</td>
                            <td data-label="Service Type">{item.type}</td>
                            <td data-label="Service Name">{item.name}</td>
                            <td data-label="Price">₹{item.totalPrice}</td>
                            <td data-label="Status">
                              <span className={`badge ${getStatusBadgeClass(item.status)}`}>
                                {item.status === "pending" ? "Upcoming" : item.status}
                              </span>
                            </td>
                            <td data-label="Action" style={{ display: "flex", gap: "10px" }}>
                              <button
                                type="button"
                                className="btn btn-sm btn-success"
                                style={{
                                  backgroundColor: item.status === "Cancelled" || item.status === "Completed" ? "#6c757d" : undefined,
                                  borderColor: item.status === "Cancelled" || item.status === "Completed" ? "#6c757d" : undefined,
                                  cursor: item.status === "Cancelled" || item.status === "Completed" ? "not-allowed" : "pointer",
                                  opacity: item.status === "Cancelled" || item.status === "Completed" ? 0.65 : 1,
                                }}
                                onClick={() => {
                                  if (item.status !== "Cancelled" && item.status !== "Completed") {
                                    setSelectedBooking(item);
                                    setNewStatus(item.status);
                                    setShowStatusModal(true);
                                  }
                                }}
                              >
                                Status
                              </button>

                              <button
                                type="button"
                                className="btn btn-sm btn-info"
                                onClick={() => handleViewModalOpen(booking, item)}
                              >
                                View
                              </button>
                              <button
                                type="button"
                                className="btn btn-sm btn-primary"
                                style={{
                                  backgroundColor: item.status === "Cancelled" ? "#6c757d" : undefined,
                                  borderColor: item.status === "Cancelled" ? "#6c757d" : undefined,
                                  cursor: item.status === "Cancelled" ? "not-allowed" : "pointer",
                                  opacity: item.status === "Cancelled" ? 0.65 : 1,
                                }}
                                disabled={item.status === "Cancelled"}
                                onClick={() => {
                                  navigate("/centre/upload-report", {
                                    state: {
                                      service: item,
                                      booking: booking,
                                      userId: booking?.userDetails?._id,
                                      bookingId: item.bookingId
                                    },
                                  });
                                }}
                              >
                                Report
                              </button>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>

                  {/* Pagination Controls */}
                  <div className="flx-between gap-2">
                    <div className="paginate-content flx-align flex-nowrap gap-3">
                      <span className="paginate-content__text fs-14">
                        Showing {indexOfFirstPackage + 1} –{" "}
                        {Math.min(indexOfLastPackage, flattenedBookings.length)}{" "}
                        of {flattenedBookings.length}
                      </span>
                    </div>
                    <nav aria-label="Doctor pagination" className="mt-3">
                      <ul className="pagination justify-content-center">
                        {renderPagination()}
                      </ul>
                    </nav>
                  </div>
                </>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* View Modal */}
      {showModal && bookingStatement && (
        <div
          style={{
            position: "fixed",
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: "rgba(0,0,0,0.5)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            zIndex: 1000,
            padding: "15px",
            overflowY: "auto",
          }}
          onClick={() => setShowModal(false)}
        >
          <div
            style={{
              backgroundColor: "#fff",
              borderRadius: "10px",
              maxWidth: "700px",
              width: "90%",
              boxShadow: "0 0 10px rgba(0,0,0,0.3)",
              position: "relative",
              overflow: "hidden",
              maxHeight: "90vh",
              overflowY: "auto",
            }}
            onClick={(e) => e.stopPropagation()}
          >
            <div
              style={{
                backgroundColor: "#3a3a3a",
                color: "#fff",
                padding: "15px 20px",
                fontSize: "18px",
                fontWeight: "bold",
                position: "sticky",
                top: 0,
                zIndex: 10,
              }}
            >
              Booking Details
              <button
                onClick={() => setShowModal(false)}
                style={{
                  position: "absolute",
                  top: "10px",
                  right: "10px",
                  background: "transparent",
                  border: "none",
                  fontSize: "22px",
                  color: "#fff",
                  cursor: "pointer",
                }}
              >
                &times;
              </button>
            </div>

            <div style={{ display: "flex", padding: "20px", flexWrap: "wrap", gap: "20px" }}>
              {/* Left Column */}
              <div style={{ flex: "1", minWidth: "250px" }}>
                <div style={{ marginBottom: "20px" }}>
                  <p><strong style={{ color: "black" }}>Booking ID</strong></p>
                  <p>{bookingStatement.item?.bookingId}</p>
                </div>
                <div style={{ marginBottom: "20px" }}>
                  <p><strong style={{ color: "black" }}>Appointment Date</strong></p>
                  <p>{bookingStatement.item?.appointmentDate}</p>
                </div>
                <div style={{ marginBottom: "20px" }}>
                  <p><strong style={{ color: "black" }}>Appointment Time</strong></p>
                  <p>{bookingStatement.item?.appointmentTime}</p>
                </div>
                <div style={{ marginBottom: "20px" }}>
                  <p><strong style={{ color: "black" }}>Patient Name</strong></p>
                  <p>{bookingStatement.booking?.userDetails?.firstName} {bookingStatement.booking?.userDetails?.lastName}</p>
                </div>
                <div style={{ marginBottom: "20px" }}>
                  <p><strong style={{ color: "black" }}>Patient Email</strong></p>
                  <p>{bookingStatement.booking?.userDetails?.email}</p>
                </div>
                <div style={{ marginBottom: "20px" }}>
                  <p><strong style={{ color: "black" }}>Patient Mobile</strong></p>
                  <p>{bookingStatement.booking?.userDetails?.mobileNumber}</p>
                </div>
              </div>

              {/* Right Column */}
              <div style={{ flex: "1", minWidth: "250px" }}>
                <div style={{ marginBottom: "20px" }}>
                  <p><strong style={{ color: "black" }}>Booking Type</strong></p>
                  <p>{bookingStatement.item?.type}</p>
                </div>
                <div style={{ marginBottom: "20px" }}>
                  <p><strong style={{ color: "black" }}>{bookingStatement.item?.type === "package" ? "Package Name" : "Service Name"}</strong></p>
                  <p>{bookingStatement.item?.name}</p>
                </div>
                <div style={{ marginBottom: "20px" }}>
                  {bookingStatement.item?.type === "package" ? (
                    <>
                      <p><strong style={{ color: "black" }}>Services Name</strong></p>
                      {bookingStatement.item?.includedServices?.map((service, key) => (
                        <p key={key}>{service}</p>
                      ))}
                    </>
                  ) : (
                    <>
                      <p><strong style={{ color: "black" }}>Category Name</strong></p>
                      <p>{bookingStatement.item?.category}</p>
                    </>
                  )}
                </div>
                <div style={{ marginBottom: "20px" }}>
                  <p><strong style={{ color: "black" }}>Doctor Name</strong></p>
                  {bookingStatement.item?.doctors?.map((doc, index) => (
                    <p key={index}>{doc}</p>
                  ))}
                </div>
                <div style={{ marginBottom: "20px" }}>
                  <p><strong style={{ color: "black" }}>Price</strong></p>
                  <p>₹{bookingStatement.item?.totalPrice}</p>
                </div>
                <div style={{ marginBottom: "20px" }}>
                  <p><strong style={{ color: "black" }}>Status</strong></p>
                  <p>{bookingStatement.item?.status === "pending" ? "Upcoming" : bookingStatement.item?.status}</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Status Update Modal */}
      {showStatusModal && selectedBooking && (
        <div
          style={{
            position: "fixed",
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: "rgba(0,0,0,0.5)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            zIndex: 1000,
          }}
          onClick={() => setShowStatusModal(false)}
        >
          <div
            style={{
              backgroundColor: "#fff",
              borderRadius: "10px",
              maxWidth: "500px",
              width: "90%",
              boxShadow: "0 0 10px rgba(0,0,0,0.3)",
              position: "relative",
              overflow: "hidden",
            }}
            onClick={(e) => e.stopPropagation()}
          >
            <div
              style={{
                backgroundColor: "#3a3a3a",
                color: "#fff",
                padding: "15px 20px",
                fontSize: "18px",
                fontWeight: "bold",
              }}
            >
              Update Status
              <button
                onClick={() => setShowStatusModal(false)}
                style={{
                  position: "absolute",
                  top: "10px",
                  right: "10px",
                  background: "transparent",
                  border: "none",
                  fontSize: "22px",
                  color: "#fff",
                  cursor: "pointer",
                }}
              >
                &times;
              </button>
            </div>

            <div style={{ padding: "20px" }}>
              <div className="mb-3">
                <label className="form-label fw-bold">Status</label>
                <select
                  className="form-select"
                  value={newStatus}
                  onChange={(e) => setNewStatus(e.target.value)}
                >
                  <option value="">-- Select Status --</option>
                  <option value="Cancelled">Cancelled</option>
                  <option value="Completed">Completed</option>
                </select>
              </div>
              <div className="d-flex justify-content-end">
                <button
                  className="btn btn-primary"
                  onClick={() =>
                    updateStatus(
                      selectedBooking.bookingId,
                      newStatus,
                      selectedBooking.appointmentDate,
                      selectedBooking.appointmentTime
                    )
                  }
                  disabled={!newStatus}
                >
                  Update
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      <style>
        {`
          /* Filters Container Styles */
          .filters-container {
            width: 100%;
            padding: 15px 0;
          }

          .filter-item {
            min-width: 180px;
          }

          .filter-select {
            width: 100%;
            padding: 8px 12px;
            border-radius: 6px;
            background-color: #fff;
            cursor: pointer;
          }

          /* Responsive Styles */
          @media (max-width: 768px) {
            .filters-container .d-flex {
              gap: 10px !important;
            }
            
            .filter-item {
              min-width: 150px;
              flex: 1 1 calc(50% - 10px);
            }
            
            .booking-heading {
              width: 100%;
              margin-bottom: 10px !important;
            }
            
            .me-auto {
              margin-right: 0 !important;
            }
          }

          @media (max-width: 576px) {
            .filter-item {
              min-width: 100%;
              flex: 1 1 100%;
            }
            
            .btn-outline-secondary {
              width: 100%;
              margin-top: 5px;
            }
          }

          @media (max-width: 426px) {
            .booking-smallscreen {
              flex-direction: column;
              align-items: flex-start;
              gap: 0px !important;
            }

            .booking-heading {
              width: 100%;
              text-align: left;
            }
          }
          
          @media (max-width: 495px) {
            .booking-selecting {
              width: 100% !important;
            }
          }
        `}
      </style>

      <ToastContainer position="top-right" autoClose={3000} />
    </div>
  );
};

export default DashboardStatement;